-- TrinityCore-evry DB Rank 1 Phase 2: creature_template.faction extended evidence
-- Build 12.0.7.68275 — normalized name / display id / quest objective
-- UPDATE-only (6010 rows); TDB entry id unchanged

CREATE TEMPORARY TABLE `tmp_creature_faction_phase2` (
  `entry` int unsigned NOT NULL,
  `faction` smallint unsigned NOT NULL,
  PRIMARY KEY (`entry`)
) ENGINE=Memory;














UPDATE `creature_template` ct
INNER JOIN `tmp_creature_faction_phase2` src ON ct.`entry` = src.`entry`
SET ct.`faction` = src.`faction`;

DROP TEMPORARY TABLE `tmp_creature_faction_phase2`;
